def map_task(chunk):
    pairs = []
    for ch in chunk:
        if ch in "aeiou":
            pairs.append((ch, 1))
    return pairs

def run(name, chunk, fail=False):
    if fail:
        return {"task": name, "chunk": chunk, "status": "failed", "pairs": None}
    return {"task": name, "chunk": chunk, "status": "done", "pairs": map_task(chunk)}

results = [
    run("t1", "data"),
    run("t2", "queue", fail=True),
    run("t3", "node"),
]

for record in results:
    if record["status"] == "failed":
        record["pairs"] = map_task(record["chunk"])
        record["status"] = "done"

totals = {}
for record in results:
    for key, count in record["pairs"]:
        totals[key] = totals.get(key, 0) + count

print(totals)
